#!/usr/bin/env bash
set -euo pipefail
cd "$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)" || { echo "❌ repo folder not found"; exit 1; }
echo "→ Syncing to origin/main…"
git fetch origin -q
git reset --hard origin/main -q
write_file() {
  local path="$1" b64="$2"
  mkdir -p "$(dirname "$path")"
  printf '%s' "$b64" | base64 --decode > "$path"
}
write_file "src/components/IntroTips.tsx" ""
write_file "src/App.tsx" ""
write_file "src/components/TopNav.tsx" ""
write_file "src/components/ChatWidget.tsx" ""
write_file "src/pages/ClientOnboarding.tsx" ""
write_file "src/pages/ContractorOnboarding.tsx" ""
write_file "CLAUDE.md" ""
echo "→ Committing…"
git add -A
git commit -q -m "First-visit coach-mark tips (Settings + chat) for logged-out visitors; superset incl. duplicate-account prevention (email/phone pre-flight + auth.users phone-unique trigger)" || { echo "Nothing to commit"; }
git push origin main
echo "✅ Done — pushed. Hard-refresh the site with Cmd+Shift+R."
